import React, { useState, useEffect, useCallback } from 'react';
import { View, Text, StyleSheet, Button, ScrollView, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo from '@react-native-community/netinfo';

const STORAGE_KEYS = {
  TOKENS: '@offline_tokens',
  ACTIONS: '@offline_actions',
  TOKEN_COUNTER: '@token_counter'
};

const TokenGenerator = {
  generateSecureToken: () => {
    const timestamp = Date.now();
    const randomPart1 = Math.floor(Math.random() * Number.MAX_SAFE_INTEGER).toString(36);
    const randomPart2 = Math.floor(Math.random() * Number.MAX_SAFE_INTEGER).toString(36);
    const randomPart3 = Math.floor(Math.random() * Number.MAX_SAFE_INTEGER).toString(36);
    const randomPart4 = Math.floor(Math.random() * Number.MAX_SAFE_INTEGER).toString(36);
    
    return `${timestamp.toString(36)}-${randomPart1}-${randomPart2}-${randomPart3}-${randomPart4}`;
  },

  generateTokenWithEntropy: async () => {
    const counter = await TokenGenerator.getAndIncrementCounter();
    const timestamp = Date.now();
    const performanceNow = typeof performance !== 'undefined' ? performance.now() : 0;
    
    const entropy = [
      timestamp,
      performanceNow,
      counter,
      Math.random(),
      Math.random(),
      Math.random()
    ].map(val => Math.floor(val * Number.MAX_SAFE_INTEGER).toString(36)).join('-');
    
    return `offline-${entropy}`;
  },

  getAndIncrementCounter: async () => {
    try {
      const counterStr = await AsyncStorage.getItem(STORAGE_KEYS.TOKEN_COUNTER);
      const counter = counterStr ? parseInt(counterStr, 10) : 0;
      await AsyncStorage.setItem(STORAGE_KEYS.TOKEN_COUNTER, (counter + 1).toString());
      return counter;
    } catch (error) {
      console.error('Counter error:', error);
      return Math.floor(Math.random() * 1000000);
    }
  }
};

const TokenManager = {
  createToken: async (userId, metadata = {}) => {
    try {
      const token = await TokenGenerator.generateTokenWithEntropy();
      const tokenData = {
        token,
        userId,
        createdAt: Date.now(),
        expiresAt: Date.now() + (24 * 60 * 60 * 1000),
        metadata,
        isOffline: true,
        synced: false
      };

      const existingTokens = await TokenManager.getTokens();
      existingTokens.push(tokenData);
      await AsyncStorage.setItem(STORAGE_KEYS.TOKENS, JSON.stringify(existingTokens));

      return tokenData;
    } catch (error) {
      console.error('Token creation error:', error);
      throw error;
    }
  },

  getTokens: async () => {
    try {
      const tokensStr = await AsyncStorage.getItem(STORAGE_KEYS.TOKENS);
      return tokensStr ? JSON.parse(tokensStr) : [];
    } catch (error) {
      console.error('Get tokens error:', error);
      return [];
    }
  },

  validateToken: async (token) => {
    try {
      const tokens = await TokenManager.getTokens();
      const tokenData = tokens.find(t => t.token === token);

      if (!tokenData) {
        return { valid: false, reason: 'Token not found' };
      }

      if (tokenData.expiresAt < Date.now()) {
        return { valid: false, reason: 'Token expired' };
      }

      return { valid: true, tokenData };
    } catch (error) {
      console.error('Token validation error:', error);
      return { valid: false, reason: 'Validation error' };
    }
  },

  cleanExpiredTokens: async () => {
    try {
      const tokens = await TokenManager.getTokens();
      const now = Date.now();
      const validTokens = tokens.filter(t => t.expiresAt > now);
      await AsyncStorage.setItem(STORAGE_KEYS.TOKENS, JSON.stringify(validTokens));
      return tokens.length - validTokens.length;
    } catch (error) {
      console.error('Clean tokens error:', error);
      return 0;
    }
  },

  markTokenAsSynced: async (token) => {
    try {
      const tokens = await TokenManager.getTokens();
      const updatedTokens = tokens.map(t => 
        t.token === token ? { ...t, synced: true, syncedAt: Date.now() } : t
      );
      await AsyncStorage.setItem(STORAGE_KEYS.TOKENS, JSON.stringify(updatedTokens));
    } catch (error) {
      console.error('Mark synced error:', error);
    }
  }
};

const ActionTracker = {
  trackAction: async (token, action, data = {}) => {
    try {
      const validation = await TokenManager.validateToken(token);
      if (!validation.valid) {
        throw new Error(`Invalid token: ${validation.reason}`);
      }

      const actionData = {
        id: await TokenGenerator.generateTokenWithEntropy(),
        token,
        action,
        data,
        timestamp: Date.now(),
        synced: false
      };

      const existingActions = await ActionTracker.getActions();
      existingActions.push(actionData);
      await AsyncStorage.setItem(STORAGE_KEYS.ACTIONS, JSON.stringify(existingActions));

      return actionData;
    } catch (error) {
      console.error('Track action error:', error);
      throw error;
    }
  },

  getActions: async () => {
    try {
      const actionsStr = await AsyncStorage.getItem(STORAGE_KEYS.ACTIONS);
      return actionsStr ? JSON.parse(actionsStr) : [];
    } catch (error) {
      console.error('Get actions error:', error);
      return [];
    }
  },

  getUnsyncedActions: async () => {
    try {
      const actions = await ActionTracker.getActions();
      return actions.filter(a => !a.synced);
    } catch (error) {
      console.error('Get unsynced actions error:', error);
      return [];
    }
  },

  markActionAsSynced: async (actionId) => {
    try {
      const actions = await ActionTracker.getActions();
      const updatedActions = actions.map(a => 
        a.id === actionId ? { ...a, synced: true, syncedAt: Date.now() } : a
      );
      await AsyncStorage.setItem(STORAGE_KEYS.ACTIONS, JSON.stringify(updatedActions));
    } catch (error) {
      console.error('Mark action synced error:', error);
    }
  }
};

const OfflineTokenApp = () => {
  const [isConnected, setIsConnected] = useState(true);
  const [currentToken, setCurrentToken] = useState(null);
  const [tokens, setTokens] = useState([]);
  const [actions, setActions] = useState([]);
  const [unsyncedCount, setUnsyncedCount] = useState(0);

  useEffect(() => {
    const unsubscribe = NetInfo.addEventListener(state => {
      setIsConnected(state.isConnected);
    });

    loadData();

    return () => unsubscribe();
  }, []);

  const loadData = async () => {
    const loadedTokens = await TokenManager.getTokens();
    const loadedActions = await ActionTracker.getActions();
    const unsynced = await ActionTracker.getUnsyncedActions();
    
    setTokens(loadedTokens);
    setActions(loadedActions);
    setUnsyncedCount(unsynced.length);
  };

  const handleGenerateToken = async () => {
    try {
      const userId = `user_${Math.floor(Math.random() * 10000)}`;
      const metadata = {
        deviceId: `device_${Math.floor(Math.random() * 10000)}`,
        platform: 'mobile'
      };

      const tokenData = await TokenManager.createToken(userId, metadata);
      setCurrentToken(tokenData);
      await loadData();
      Alert.alert('Success', 'Token generated successfully');
    } catch (error) {
      Alert.alert('Error', 'Failed to generate token');
    }
  };

  const handleTrackAction = async () => {
    if (!currentToken) {
      Alert.alert('Error', 'Please generate a token first');
      return;
    }

    try {
      const actionData = {
        type: 'user_interaction',
        details: `Action at ${new Date().toISOString()}`
      };

      await ActionTracker.trackAction(currentToken.token, 'test_action', actionData);
      await loadData();
      Alert.alert('Success', 'Action tracked successfully');
    } catch (error) {
      Alert.alert('Error', error.message);
    }
  };

  const handleSyncData = async () => {
    if (!isConnected) {
      Alert.alert('Error', 'No internet connection');
      return;
    }

    try {
      const unsyncedActions = await ActionTracker.getUnsyncedActions();
      
      for (const action of unsyncedActions) {
        await new Promise(resolve => setTimeout(resolve, 100));
        await ActionTracker.markActionAsSynced(action.id);
        await TokenManager.markTokenAsSynced(action.token);
      }

      await loadData();
      Alert.alert('Success', `Synced ${unsyncedActions.length} actions`);
    } catch (error) {
      Alert.alert('Error', 'Sync failed');
    }
  };

  const handleCleanup = async () => {
    try {
      const removed = await TokenManager.cleanExpiredTokens();
      await loadData();
      Alert.alert('Success', `Removed ${removed} expired tokens`);
    } catch (error) {
      Alert.alert('Error', 'Cleanup failed');
    }
  };

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>Offline Token Manager</Text>
        <View style={[styles.statusBadge, isConnected ? styles.online : styles.offline]}>
          <Text style={styles.statusText}>{isConnected ? 'Online' : 'Offline'}</Text>
        </View>
      </View>

      <View style={styles.stats}>
        <Text style={styles.statText}>Total Tokens: {tokens.length}</Text>
        <Text style={styles.statText}>Total Actions: {actions.length}</Text>
        <Text style={styles.statText}>Unsynced: {unsyncedCount}</Text>
      </View>

      <View style={styles.buttonContainer}>
        <Button title="Generate Token" onPress={handleGenerateToken} />
        <Button title="Track Action" onPress={handleTrackAction} disabled={!currentToken} />
        <Button title="Sync Data" onPress={handleSyncData} disabled={!isConnected} />
        <Button title="Clean Expired" onPress={handleCleanup} />
      </View>

      {currentToken && (
        <View style={styles.currentToken}>
          <Text style={styles.sectionTitle}>Current Token:</Text>
          <Text style={styles.tokenText} numberOfLines={2}>{currentToken.token}</Text>
          <Text style={styles.tokenInfo}>User: {currentToken.userId}</Text>
          <Text style={styles.tokenInfo}>
            Expires: {new Date(currentToken.expiresAt).toLocaleString()}
          </Text>
        </View>
      )}

      <ScrollView style={styles.scrollView}>
        <Text style={styles.sectionTitle}>Recent Actions:</Text>
        {actions.slice(-5).reverse().map((action, index) => (
          <View key={index} style={styles.actionItem}>
            <Text style={styles.actionText}>{action.action}</Text>
            <Text style={styles.actionTime}>
              {new Date(action.timestamp).toLocaleTimeString()}
            </Text>
            <Text style={[styles.syncStatus, action.synced ? styles.synced : styles.unsynced]}>
              {action.synced ? 'Synced' : 'Pending'}
            </Text>
          </View>
        ))}
      </ScrollView>
    </View>
  );
};

